#include <bits/stdc++.h>
using namespace std;
struct stu{
    int all,cm,mcm,num;
}s[10004];

bool cmp(stu a,stu b){
    if(a.all==b.all){
        if(a.cm==b.cm){
            return a.mcm>b.mcm;
        }
        return a.cm>b.cm;
    }
    return a.all>b.all;
}

int n,ans[10004];
int main(){
    cin>>n;
    for(int i=1;i<=n;i++){
        int c,m,e;
        cin>>c>>m>>e;
        s[i].all=c+m+e;
        s[i].cm=c+m;
        s[i].mcm=max(c,m);
        s[i].num=i;
    }
    sort(s+1,s+n+1,cmp);
    int sum=0;
    for(int i=1;i<=n;i++){
        sum++;
        if(i>1 && s[i].all==s[i-1].all && s[i].cm==s[i-1].cm && s[i].mcm==s[i-1].mcm)sum--;
        else sum=i;
        ans[s[i].num]=sum;
    }
    for(int i=1;i<=n;i++){
        cout<<ans[i]<<endl;
    }
    return 0;
}
